const result = $json;
let fullText = '';
if (result.content && result.content.html) {
  fullText = result.content.html.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
} else if (result.content && result.content.text) {
  fullText = result.content.text;
} else if (result.pages) {
  fullText = result.pages.map(p => p.text || '').join('\n');
}
const name = $('프로필 폼').item.json['이름'] || 'User';
const email = $('프로필 폼').item.json['이메일'] || '';
return [{ json: { parsedText: fullText.substring(0, 4000), name, email } }];

const { parsedText, name, email } = $json;
const body = JSON.stringify({
  model: 'solar-pro3',
  messages: [
    {
      role: 'system',
      content: `당신은 커리어 분석 전문가입니다. 아래 문서를 분석하고 반드시 JSON 형식으로만 응답하세요:
{
  "major": "전공 또는 전문 분야",
  "career_goal": "희망 진로",
  "keywords_en": ["영어키워드1","영어키워드2","영어키워드3"],
  "keywords_kr": ["한국어1","한국어2","한국어3"],
  "company": "관심 기업명 (없으면 빈 문자열)",
  "summary": "이 사람을 한 줄로 요약",
  "career_analysis": "이 사람이 지금까지 해온 것들과 강점, 방향성을 3-4문장으로 따뜻하게 분석. 반드시 '당신은'으로 시작",
  "strengths": ["강점1","강점2","강점3"],
  "growth_areas": ["성장 포인트1","성장 포인트2"],
  "department": "단과대/학부 분야 (예: 전기전자, 컴퓨터, 경영, 의학, 기계 등 영문으로)"
}`
    },
    { role: 'user', content: `이 문서를 분석해줘:

${parsedText}` }
  ],
  max_tokens: 1000
});
return [{ json: { body, name, email } }];

const raw = $json.choices[0].message.content;
const name = $('커리어 분석 프롬프트').item.json.name;
const email = $('커리어 분석 프롬프트').item.json.email;
let p;
try {
  p = JSON.parse(raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim());
} catch(e) {
  p = { major:'미분류', career_goal:'미설정', keywords_en:['AI','technology'], keywords_kr:['AI','기술'], company:'', summary:'분석 오류', career_analysis:'분석 중 오류가 발생했습니다.', strengths:[], growth_areas:[], department:'engineering' };
}
const profile = {
  name, email,
  major: p.major,
  career_goal: p.career_goal,
  keywords_en: p.keywords_en || [],
  keywords_kr: p.keywords_kr || [],
  company: p.company || '',
  summary: p.summary,
  career_analysis: p.career_analysis,
  strengths: p.strengths || [],
  growth_areas: p.growth_areas || [],
  department: p.department || 'engineering',
  updatedAt: new Date().toISOString()
};
const base64 = Buffer.from(JSON.stringify(profile, null, 2)).toString('base64');
return [{ json: profile, binary: { data: { data: base64, mimeType: 'application/json', fileName: 'user_profile.json' } } }];

// Upstage Embeddings 준비
const profile = $json;
const parsedText = $('텍스트 추출').item.json.parsedText || '';
const embeddingInput = `이름: ${profile.name}
전공: ${profile.major}
희망진로: ${profile.career_goal}
관심분야: ${[...profile.keywords_en, ...profile.keywords_kr].join(', ')}
강점: ${profile.strengths.join(', ')}

${parsedText}`.substring(0, 2000);
const body = JSON.stringify({ model: 'embedding-passage', input: embeddingInput });
return [{ json: { body, profile } }];

const embedding = $json.data[0].embedding;
const profile = $('임베딩 준비').item.json.profile;
return [{ json: { body: JSON.stringify({
  name: profile.name,
  email: profile.email,
  summary: profile.summary,
  major: profile.major,
  career_goal: profile.career_goal,
  keywords: [...(profile.keywords_en||[]), ...(profile.keywords_kr||[])],
  embedding
}) } }];

const profile = $json;
const kwEn = (profile.keywords_en || []).slice(0,3).join(' OR ');
const kwKr = (profile.keywords_kr || []).slice(0,3).join(' ');
const company = profile.company || '';
const dept = profile.department || 'engineering';

const deptMap = {
  'electrical': '전기전자공학부', 'electronic': '전기전자공학부',
  'computer': '컴퓨터공학부', 'software': '소프트웨어학부',
  'mechanical': '기계공학부', 'chemical': '화학공학부',
  'business': '경영학부', 'medicine': '의과대학',
  'physics': '물리학부', 'math': '수학과', 'engineering': '공과대학'
};
const deptName = Object.entries(deptMap).find(([k]) => dept.toLowerCase().includes(k))?.[1] || '공과대학';

const feeds = [
  { type: '링커리어', url: `https://news.google.com/rss/search?q=${encodeURIComponent('site:linkareer.com ' + kwKr)}&hl=ko&gl=KR&ceid=KR:ko` },
  { type: '대외활동/공모전', url: `https://news.google.com/rss/search?q=${encodeURIComponent(kwKr + ' 공모전 대외활동 모집')}&hl=ko&gl=KR&ceid=KR:ko` },
  { type: '인턴십/채용', url: `https://news.google.com/rss/search?q=${encodeURIComponent(kwKr + ' 인턴 채용 모집')}&hl=ko&gl=KR&ceid=KR:ko` },
  { type: '업계뉴스(한)', url: `https://news.google.com/rss/search?q=${encodeURIComponent(kwKr)}&hl=ko&gl=KR&ceid=KR:ko` },
  { type: '업계뉴스(영)', url: `https://news.google.com/rss/search?q=${encodeURIComponent(kwEn)}&hl=en&gl=US&ceid=US:en` },
  { type: '기업뉴스', url: company ? `https://news.google.com/rss/search?q=${encodeURIComponent(company)}&hl=ko&gl=KR&ceid=KR:ko` : `https://news.google.com/rss/search?q=${encodeURIComponent(kwKr + ' 기업 뉴스')}&hl=ko&gl=KR&ceid=KR:ko` },
  { type: '대학공지/세미나', url: `https://news.google.com/rss/search?q=${encodeURIComponent(deptName + ' 세미나 특강 공지 모집')}&hl=ko&gl=KR&ceid=KR:ko` },
  { type: 'HackerNews', url: 'https://hnrss.org/frontpage?count=10' }
];

return feeds.map(f => ({ json: { url: f.url, type: f.type, profile, deptName } }));

// 각 RSS 응답을 파싱해서 타이틀 추출
const xml = $json.data || '';
const type = $('데이터 수집').item.json.type;
const profile = $('데이터 수집').item.json.profile;
const deptName = $('데이터 수집').item.json.deptName;

function parseTitles(xml, max) {
  const items = [];
  const itemMatches = xml.matchAll(/<item>([\s\S]*?)<\/item>/g);
  for (const m of itemMatches) {
    const block = m[1];
    const titleMatch = block.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/);
    const title = titleMatch ? titleMatch[1].replace(/<[^>]*>/g,'').trim() : '';
    if (title && !title.includes('Google News') && title.length > 5) items.push(title);
    if (items.length >= max) break;
  }
  return items;
}

const titles = parseTitles(xml, 6);
return [{ json: { type, titles, profile, deptName } }];

// 모든 RSS 결과를 하나로 합치기
const allItems = $input.all();
const results = {};
let profile = null;
let deptName = '공과대학';

for (const item of allItems) {
  const { type, titles } = item.json;
  if (!profile) {
    profile = item.json.profile;
    deptName = item.json.deptName;
  }
  results[type] = titles || [];
}

const fmt = (type, max) => {
  const items = results[type] || [];
  return items.length > 0 ? items.slice(0,max).map((t,i) => `${i+1}. ${t}`).join('
') : '현재 관련 정보가 없습니다.';
};

const allContent = `[링커리어 대외활동]
${fmt('링커리어',5)}

[공모전/대외활동]
${fmt('대외활동/공모전',5)}

[인턴십/채용]
${fmt('인턴십/채용',5)}

[업계뉴스(한국어)]
${fmt('업계뉴스(한)',5)}

[업계뉴스(영어)]
${fmt('업계뉴스(영)',4)}

[기업뉴스]
${fmt('기업뉴스',3)}

[대학공지/세미나 - ${deptName}]
${fmt('대학공지/세미나',5)}

[HackerNews]
${fmt('HackerNews',4)}`;

const body = JSON.stringify({
  model: 'solar-pro3',
  messages: [
    {
      role: 'system',
      content: `당신은 ${profile.name}님의 전담 커리어 코치입니다.

프로필:
- 전공: ${profile.major}
- 희망 진로: ${profile.career_goal}
- 관심 분야: ${[...profile.keywords_en, ...profile.keywords_kr].join(', ')}
- 강점: ${(profile.strengths||[]).join(', ')}

⚠️ 반드시 아래 제공된 실제 데이터만 사용하세요. 없는 정보는 절대 만들지 마세요.

아래 5개 섹션으로 작성:

🏆 오늘 신청할 대외활동/공모전
(각 항목: 제목 + ${profile.name}님에게 왜 좋은지 한 줄)

💼 놓치면 안될 채용/인턴 정보
(각 항목: 제목 + 왜 지원해볼만한지 한 줄)

📰 오늘 꼭 읽어야 할 업계 뉴스
(각 항목: 제목 + 핵심 한 줄 요약 + ${profile.name}님과의 관련성)

🎓 ${deptName} 관련 대학 공지/세미나
(각 항목: 제목 + 참여 추천 이유)

🎯 오늘의 커리어 미션
(구체적이고 실천 가능한 행동 1가지)`
    },
    { role: 'user', content: allContent }
  ],
  max_tokens: 3000
});

return [{ json: { body, profile, deptName } }];
